+func TestCASSContextValidation(t *testing.T) {
+	tests := []struct {
+		name    string
+		cfg     Config
+		wantErr bool
+		errPath string
+	}{
+		{
+			name: "valid context config",
+			cfg: Config{
+				CASS: CASSConfig{
+					Timeout: 30,
+					Context: CASSContextConfig{
+						MaxSessions:        3,
+						LookbackDays:       30,
+						MaxTokens:          2000,
+						MinRelevance:       0.5,
+						SkipIfContextAbove: 80,
+					},
+				},
+				Tmux:            TmuxConfig{DefaultPanes: 1},
+				ContextRotation: DefaultContextRotationConfig(),
+				Health:          DefaultHealthConfig(),
+			},
+			wantErr: false,
+		},
+		{
+			name: "min_relevance too low",
+			cfg: Config{
+				CASS: CASSConfig{
+					Timeout: 30,
+					Context: CASSContextConfig{
+						MinRelevance:       -0.1,
+						SkipIfContextAbove: 80,
+					},
+				},
+				Tmux:            TmuxConfig{DefaultPanes: 1},
+				ContextRotation: DefaultContextRotationConfig(),
+				Health:          DefaultHealthConfig(),
+			},
+			wantErr: true,
+			errPath: "cass.context.min_relevance",
+		},
+		{
+			name: "min_relevance too high",
+			cfg: Config{
+				CASS: CASSConfig{
+					Timeout: 30,
+					Context: CASSContextConfig{
+						MinRelevance:       1.5,
+						SkipIfContextAbove: 80,
+					},
+				},
+				Tmux:            TmuxConfig{DefaultPanes: 1},
+				ContextRotation: DefaultContextRotationConfig(),
+				Health:          DefaultHealthConfig(),
+			},
+			wantErr: true,
+			errPath: "cass.context.min_relevance",
+		},
+		{
+			name: "skip_if_context_above too low",
+			cfg: Config{
+				CASS: CASSConfig{
+					Timeout: 30,
+					Context: CASSContextConfig{
+						MinRelevance:       0.5,
+						SkipIfContextAbove: -10,
+					},
+				},
+				Tmux:            TmuxConfig{DefaultPanes: 1},
+				ContextRotation: DefaultContextRotationConfig(),
+				Health:          DefaultHealthConfig(),
+			},
+			wantErr: true,
+			errPath: "cass.context.skip_if_context_above",
+		},
+		{
+			name: "skip_if_context_above too high",
+			cfg: Config{
+				CASS: CASSConfig{
+					Timeout: 30,
+					Context: CASSContextConfig{
+						MinRelevance:       0.5,
+						SkipIfContextAbove: 150,
+					},
+				},
+				Tmux:            TmuxConfig{DefaultPanes: 1},
+				ContextRotation: DefaultContextRotationConfig(),
+				Health:          DefaultHealthConfig(),
+			},
+			wantErr: true,
+			errPath: "cass.context.skip_if_context_above",
+		},
+		{
+			name: "max_sessions negative",
+			cfg: Config{
+				CASS: CASSConfig{
+					Timeout: 30,
+					Context: CASSContextConfig{
+						MaxSessions:        -1,
+						MinRelevance:       0.5,
+						SkipIfContextAbove: 80,
+					},
+				},
+				Tmux:            TmuxConfig{DefaultPanes: 1},
+				ContextRotation: DefaultContextRotationConfig(),
+				Health:          DefaultHealthConfig(),
+			},
+			wantErr: true,
+			errPath: "cass.context.max_sessions",
+		},
+		{
+			name: "max_tokens negative",
+			cfg: Config{
+				CASS: CASSConfig{
+					Timeout: 30,
+					Context: CASSContextConfig{
+						MaxTokens:          -100,
+						MinRelevance:       0.5,
+						SkipIfContextAbove: 80,
+					},
+				},
+				Tmux:            TmuxConfig{DefaultPanes: 1},
+				ContextRotation: DefaultContextRotationConfig(),
+				Health:          DefaultHealthConfig(),
+			},
+			wantErr: true,
+			errPath: "cass.context.max_tokens",
+		},
+		{
+			name: "lookback_days negative",
+			cfg: Config{
+				CASS: CASSConfig{
+					Timeout: 30,
+					Context: CASSContextConfig{
+						LookbackDays:       -7,
